@page "/"
@rendermode InteractiveAuto

@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@inject NavigationManager Navigation

<PageTitle>ShipmentTracker - Home</PageTitle>

<h1>Track Your Shipment</h1>
<p class="lead">Enter your tracking number to check shipment status and estimated delivery.</p>

<div class="row mt-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (errorMessage is not null)
{
    <div class="alert alert-warning mt-3 col-md-6">@errorMessage</div>
}

@if (trackedShipment is not null)
{
    <div class="card mt-4 col-md-8">
        <div class="card-header">
            <strong>Shipment @trackedShipment.TrackingNumber</strong>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-4">Status</dt>
                <dd class="col-sm-8"><span class="badge bg-@GetStatusColor(trackedShipment.Status)">@trackedShipment.Status</span></dd>
                <dt class="col-sm-4">Origin</dt>
                <dd class="col-sm-8">@trackedShipment.Origin</dd>
                <dt class="col-sm-4">Destination</dt>
                <dd class="col-sm-8">@trackedShipment.Destination</dd>
                <dt class="col-sm-4">Description</dt>
                <dd class="col-sm-8">@trackedShipment.Description</dd>
                <dt class="col-sm-4">Shipped</dt>
                <dd class="col-sm-8">@trackedShipment.ShippedDate.ToString("MMM dd, yyyy")</dd>
                <dt class="col-sm-4">Estimated Delivery</dt>
                <dd class="col-sm-8"><strong>@trackedShipment.EstimatedDelivery.ToString("MMM dd, yyyy")</strong></dd>
            </dl>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private Shipment? trackedShipment;
    private string? errorMessage;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isLoading = true;
        errorMessage = null;
        trackedShipment = null;

        try
        {
            trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
            if (trackedShipment is null)
                errorMessage = "No shipment found with that tracking number.";
        }
        catch
        {
            errorMessage = "Unable to look up shipment. Please try again.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.InTransit => "info",
        ShipmentStatus.OutForDelivery => "primary",
        ShipmentStatus.Delayed => "danger",
        ShipmentStatus.PickedUp => "secondary",
        _ => "warning"
    };
}

@page "/my-shipments"
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@using Microsoft.AspNetCore.Components.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@inject AuthenticationStateProvider AuthStateProvider

<PageTitle>My Shipments</PageTitle>

<h1>My Shipments</h1>

@if (isLoading)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <div class="alert alert-info">You have no shipments yet.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Description</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Estimated Delivery</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in shipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Description</td>
                        <td>@s.Destination</td>
                        <td><span class="badge bg-@GetStatusColor(s.Status)">@s.Status</span></td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<Shipment> shipments = [];
    private bool isLoading = true;

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthStateProvider.GetAuthenticationStateAsync();
        var email = authState.User.Identity?.Name ?? string.Empty;

        try
        {
            shipments = await ShipmentService.GetShipmentsForCustomerAsync(email);
        }
        catch
        {
            shipments = [];
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.InTransit => "info",
        ShipmentStatus.OutForDelivery => "primary",
        ShipmentStatus.Delayed => "danger",
        ShipmentStatus.PickedUp => "secondary",
        _ => "warning"
    };
}

@page "/dispatch"
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Dispatch Dashboard</PageTitle>

<h1>Dispatch Dashboard</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="filterStatus">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
</div>

@if (isLoading)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Customer</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.CustomerEmail</td>
                        <td><span class="badge bg-@GetStatusColor(s.Status)">@s.Status</span></td>
                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm" value="@s.Status"
                                    @onchange="e => UpdateStatus(s, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<Shipment> shipments = [];
    private bool isLoading = true;
    private string filterText = string.Empty;
    private string filterStatus = string.Empty;

    private IEnumerable<Shipment> FilteredShipments => shipments
        .Where(s => string.IsNullOrEmpty(filterText) ||
                    s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        .Where(s => string.IsNullOrEmpty(filterStatus) ||
                    s.Status.ToString() == filterStatus);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch
        {
            shipments = [];
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.InTransit => "info",
        ShipmentStatus.OutForDelivery => "primary",
        ShipmentStatus.Delayed => "danger",
        ShipmentStatus.PickedUp => "secondary",
        _ => "warning"
    };
}

